package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.Serializable;
import java.io.StringWriter;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;

public class CSVFormatTest {

    private Reader readerMock;

    @BeforeEach
    public void setUp() {
        readerMock = mock(Reader.class);
    }

    @Test
    public void testParseReturnsCSVParserInstance() throws IOException {
        try (MockedConstruction<CSVParser> mocked = mockConstruction(CSVParser.class,
                (mock, context) -> {
                    // no-op, just to verify construction
                })) {
            CSVFormat format = CSVFormat.DEFAULT;
            CSVParser parser = format.parse(readerMock);

            // Verify CSVParser constructor called once with readerMock and format
            assertNotNull(parser);
            assertEquals(1, mocked.constructed().size());
            CSVParser constructedParser = mocked.constructed().get(0);
            assertSame(parser, constructedParser);
        }
    }

    @Test
    public void testParseThrowsIOException() throws IOException {
        // Mock CSVParser constructor to throw IOException
        try (MockedConstruction<CSVParser> mocked = mockConstruction(CSVParser.class,
                (mock, context) -> {
                    doThrow(new IOException("Mock IOException")).when(mock).close();
                })) {
            CSVFormat format = CSVFormat.DEFAULT;
            // We cannot throw IOException from constructor directly with mockConstruction,
            // so simulate by mocking CSVParser constructor to throw IOException via spy or other means is not possible.
            // Instead, test parse normally since parse just calls new CSVParser(in, this).
            // So no direct way to test IOException thrown by CSVParser constructor here.

            // So we just verify parse returns instance without exception
            CSVParser parser = format.parse(readerMock);
            assertNotNull(parser);
        }
    }
}
